import anthropic
from datasets import load_dataset
from pathlib import Path
import re

client = anthropic.Anthropic()

TOOLS = [
    {
        "name": "web_search",
        "description": "Search the web for current information",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search query"}
            },
            "required": ["query"],
        },
    },
    {
        "name": "python_eval",
        "description": "Execute Python code and return stdout",
        "input_schema": {
            "type": "object",
            "properties": {
                "code": {"type": "string", "description": "Python code to run"}
            },
            "required": ["code"],
        },
    },
    {
        "name": "read_file",
        "description": "Read a text or PDF file by path",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "Absolute file path"}
            },
            "required": ["path"],
        },
    },
]

SYSTEM = """You are a general-purpose assistant solving research questions.
Use tools as needed. When you have the final answer, respond with:
FINAL ANSWER: <answer>
The answer must be a precise string — no extra explanation after it."""


def dispatch_tool(name: str, inp: dict) -> str:
    """Stub dispatcher — replace with real implementations."""
    if name == "web_search":
        return f"[Search results for: {inp['query']}]"
    if name == "python_eval":
        import subprocess, sys
        result = subprocess.run(
            [sys.executable, "-c", inp["code"]],
            capture_output=True, text=True, timeout=10
        )
        return result.stdout or result.stderr
    if name == "read_file":
        try:
            return Path(inp["path"]).read_text(errors="replace")[:4000]
        except Exception as e:
            return f"Error: {e}"
    return "Unknown tool"


def extract_final_answer(text: str) -> str:
    """Parse 'FINAL ANSWER: ...' from model output."""
    m = re.search(r"FINAL ANSWER:\s*(.+)", text, re.IGNORECASE)
    return m.group(1).strip() if m else text.strip()


def solve_gaia_task(question: str, file_path: str = "") -> str:
    messages = []
    if file_path:
        messages.append({
            "role": "user",
            "content": f"File available at: {file_path}\n\nQuestion: {question}",
        })
    else:
        messages.append({"role": "user", "content": question})

    for _ in range(25):  # cap at 25 turns for L3
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            system=SYSTEM,
            tools=TOOLS,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            text = next(
                (b.text for b in response.content if hasattr(b, "text")), ""
            )
            return extract_final_answer(text)

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = dispatch_tool(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result[:3000],  # truncate to avoid overflow
                    })
            messages += [
                {"role": "assistant", "content": response.content},
                {"role": "user", "content": tool_results},
            ]

    return ""
